#include <iostream>
#include <functional>
#include <array>

int main()
{
    int a{}, b{}, c{};
    std::cin >> a >> b >> c;

    std::array<std::reference_wrapper<int>, 3> refs{ std::ref(a), std::ref(b), std::ref(c) };

    int k{};
    std::cin >> k;

    for (int i{ 0 }; i < k; ++i)
    {
        refs[static_cast<std::size_t>(i)].get() *= 2;
    }

    std::cout << a << ' ' << b << ' ' << c << '\n';

    return 0;
}

